SELECT COUNT(*) FROM hm_query.page_views_flat

    AND user_id = #{userId}
    AND session_id = #{sessionId}
    AND page_type = #{pageType}
    AND device_type = #{deviceType}
    AND country = #{country}
    AND created_time >= #{startDate}
    AND created_time <= #{endDate}
    AND (page_url LIKE CONCAT('%', #{q}, '%') OR referrer_url LIKE CONCAT('%', #{q}, '%'))

SELECT id, session_id AS "sessionId", user_id AS "userId",
       page_url AS "pageUrl", page_type AS "pageType",
       referrer_url AS "referrerUrl", device_type AS "deviceType",
       browser, ip_address AS "ipAddress", country,
       duration_ms AS "durationMs", created_time AS "createdTime"
FROM hm_query.page_views_flat

    AND user_id = #{userId}
    AND session_id = #{sessionId}
    AND page_type = #{pageType}
    AND device_type = #{deviceType}
    AND country = #{country}
    AND created_time >= #{startDate}
    AND created_time <= #{endDate}
    AND (page_url LIKE CONCAT('%', #{q}, '%') OR referrer_url LIKE CONCAT('%', #{q}, '%'))

${orderby} ${pagination}

SELECT COUNT(*) FROM hm_query.click_events_flat

    AND user_id = #{userId}
    AND session_id = #{sessionId}
    AND element_type = #{elementType}
    AND element_id = #{elementId}
    AND created_time >= #{startDate}
    AND created_time <= #{endDate}

SELECT id, session_id AS "sessionId", user_id AS "userId",
       element_type AS "elementType", element_id AS "elementId",
       page_url AS "pageUrl", event_data_json AS "eventDataJson",
       created_time AS "createdTime"
FROM hm_query.click_events_flat

    AND user_id = #{userId}
    AND session_id = #{sessionId}
    AND element_type = #{elementType}
    AND element_id = #{elementId}
    AND created_time >= #{startDate}
    AND created_time <= #{endDate}

${orderby} ${pagination}
